// Wait for the entire HTML document (DOM) to be fully loaded and parsed before executing
document.addEventListener('DOMContentLoaded', () => {
    // Select all elements with the class 'alert' (flash messages generated by Flask)
    const alerts = document.querySelectorAll('.alert');

    // Check if there are any alert messages currently on screen
    if (alerts.length > 0) {
        // Set a timer to initiate the fade-out effect after 5000 milliseconds (5 seconds)
        setTimeout(() => {
            // Iterate over each alert message element
            alerts.forEach(alert => {
                // Apply a CSS transition for a smooth visual 'opacity' fade over 0.5s
                alert.style.transition = 'opacity 0.5s ease';
                // Trigger the fade-out by setting opacity to 0 (invisible)
                alert.style.opacity = '0';

                // Wait an additional 500ms for the animation to finish, then safely remove the element from the DOM
                setTimeout(() => alert.remove(), 500);
            });
        }, 5000); // 5 seconds display duration
    }
});

